@reference "../../../index.css";

.greeting {
  @apply mb-6;
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  justify-content: space-between;
}

.greeting__title {
  @apply text-ink;
  font-size: 30px;
  line-height: 1.2;
  margin-bottom: 8px;
}

.greeting__sub {
  @apply text-ink-muted max-w-md;
}

.greeting__actions {
  display: flex;
  align-items: flex-start;
  gap: 8px;
}

.greeting__download {
  font-size: 15px;
  line-height: 1.5;
  margin-bottom: 8px;
  padding: 11px 14px;
  border-radius: 8px;
  border: 1px solid var(--color-line);
  background-color: var(--color-surface);
  color: var(--color-ink);
  cursor: pointer;
}

.greeting__select-wrapper {
  position: relative;
  display: inline-block;
}

.greeting__select {
  @apply text-ink-muted;
  font-size: 15px;
  line-height: 1.5;
  margin-bottom: 8px;
  padding: 11px 40px 11px 14px;
  border-radius: 8px;
  border: 1px solid var(--color-line);
  background-color: var(--color-surface);
  color: var(--color-ink);
  appearance: none;
  cursor: pointer;
  option {
    background-color: var(--color-surface);
    color: var(--color-ink);
  }
}

.greeting__select-icon {
  position: absolute;
  right: 12px;
  top: 50%;
  transform: translateY(-50%) translateY(-4px); /* adjust for margin-bottom */
  pointer-events: none;
  color: var(--color-ink-muted);
}

.greeting__share-result {
  width: 100%;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 8px;
  margin-top: 12px;
  padding: 10px 12px;
  border-radius: 8px;
  border: 1px solid var(--color-accent);
  background-color: var(--color-accent-soft);
}

.greeting__share-success {
  font-size: 14px;
  line-height: 1.5;
  margin: 0;
  word-break: break-all;
  color: var(--color-accent);
}

.greeting__share-link {
  color: var(--color-accent);
  text-decoration: underline;
}

.greeting__share-copy {
  font-size: 13px;
  line-height: 1.4;
  padding: 6px 10px;
  border-radius: 6px;
  border: 1px solid var(--color-accent);
  background-color: var(--color-surface);
  color: var(--color-accent);
  cursor: pointer;
}

.greeting__share-close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  font-size: 18px;
  line-height: 1;
  border-radius: 50%;
  border: 1px solid var(--color-accent);
  background-color: var(--color-surface);
  color: var(--color-accent);
  cursor: pointer;
}

.greeting__share-error {
  margin-top: 8px;
  font-size: 14px;
  color: #b00020;
}

